/* Ship terminal — type the real commands. pointer-events back on so the
   Drone Bay's ADD TO SHIP button is clickable (#ui is pointer-events:none). */
#terminal {
  position: absolute;
  pointer-events: auto;
  bottom: 70px;
  left: 50%;
  transform: translateX(-50%);
  width: min(560px, calc(100vw - 40px));
  padding: 14px 16px;
  background: rgba(4, 10, 18, 0.88);
  border: 1px solid rgba(111, 227, 255, 0.42);
  border-radius: 8px;
  box-shadow: 0 14px 40px rgba(2, 4, 10, 0.55), 0 0 24px rgba(111, 227, 255, 0.12);
  backdrop-filter: blur(6px);
  text-align: left;
}

#term-hint {
  font-size: 12.5px;
  letter-spacing: 0.02em;
  color: var(--ink);
  opacity: 0.68;
  margin-bottom: 10px;
}

#term-line {
  display: flex;
  align-items: center;
  font-size: 16px;
  letter-spacing: 0.02em;
}

.term-prompt {
  color: var(--accent);
  opacity: 0.9;
  margin-right: 8px;
}

#term-input { color: var(--ink); white-space: pre; }
#term-input.is-dim { color: var(--accent-warm); opacity: 0.92; }

/* Call-to-action: the actionable command/keys — the brightest thing here */
#term-cta {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-top: 13px;
}
#term-cta:empty { display: none; }
.cta-label {
  font-size: 10px;
  letter-spacing: 0.24em;
  font-weight: 700;
  color: var(--accent);
  opacity: 0.9;
}
.cta-cmd {
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 16px;
  font-weight: 700;
  letter-spacing: 0.02em;
  color: #04121a;
  padding: 5px 14px;
  border-radius: 7px;
  background: linear-gradient(90deg, #6fe3ff, #9af0ff);
  box-shadow: 0 0 18px rgba(111, 227, 255, 0.45);
}
.cta-key {
  display: inline-grid;
  place-items: center;
  min-width: 26px;
  height: 26px;
  padding: 0 7px;
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 14px;
  font-weight: 700;
  border-radius: 6px;
  color: #04121a;
}

