* { margin: 0; padding: 0; box-sizing: border-box; }

html, body {
  width: 100%;
  height: 100%;
  overflow: hidden;
  background: #02040a;
  color: var(--ink);
  font-family: "SF Mono", "JetBrains Mono", ui-monospace, Menlo, monospace;
  cursor: default;
}

#scene {
  position: fixed;
  inset: 0;
  display: block;
  width: 100%;
  height: 100%;
}

#ui {
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 10;
}

#hud {
  position: absolute;
  top: 28px;
  left: 32px;
}

.hud-title {
  font-size: 26px;
  letter-spacing: 0.42em;
  font-weight: 600;
  text-shadow: 0 0 18px rgba(111, 227, 255, 0.55);
}

#hint {
  position: absolute;
  bottom: 26px;
  left: 50%;
  transform: translateX(-50%);
  font-size: 12px;
  letter-spacing: 0.12em;
  opacity: 0.55;
  white-space: nowrap;
}

/* ---------- title screen (arcade boot menu) ---------- */

/* The orbit view keeps rendering behind it — only a soft vignette for
   legibility, so the planet stays the attract backdrop. */
#title-screen {
  position: absolute;
  inset: 0;
  z-index: 35;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  pointer-events: auto;
  background: radial-gradient(ellipse at 50% 44%, rgba(2, 4, 10, 0.55), rgba(2, 4, 10, 0.85));
  transition: opacity 0.6s ease;
}
#title-screen.is-leaving {
  opacity: 0;
  pointer-events: none;
}
#title-screen.hidden { display: none; }

/* While the title is up, the in-game chrome stays out of the shot. */
body.title-up #hud,
body.title-up #hint,
body.title-up #audio-panel,
body.title-up #island-pin { display: none !important; }
body.title-up #title-screen.is-story ~ #island-pin:not(.hidden) {
/* Ship terminal — type the real commands. pointer-events back on so the
   Drone Bay's ADD TO SHIP button is clickable (#ui is pointer-events:none). */
#terminal {
  position: absolute;
  pointer-events: auto;
  bottom: 70px;
  left: 50%;
  transform: translateX(-50%);
  width: min(560px, calc(100vw - 40px));
  padding: 14px 16px;
  background: rgba(4, 10, 18, 0.88);
  border: 1px solid rgba(111, 227, 255, 0.42);
  border-radius: 8px;
  box-shadow: 0 14px 40px rgba(2, 4, 10, 0.55), 0 0 24px rgba(111, 227, 255, 0.12);
  backdrop-filter: blur(6px);
  text-align: left;
}

#term-hint {
  font-size: 12.5px;
  letter-spacing: 0.02em;
  color: var(--ink);
  opacity: 0.68;
  margin-bottom: 10px;
}

#term-line {
  display: flex;
  align-items: center;
  font-size: 24px;
  letter-spacing: 0.02em;
}

.term-prompt {
  color: var(--accent);
  opacity: 0.9;
  margin-right: 8px;
}

#term-input { color: var(--ink); white-space: pre; }
#term-input.is-dim { color: var(--accent-warm); opacity: 0.92; }

/* Call-to-action: the actionable command/keys — the brightest thing here */
#term-cta {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-top: 13px;
}
#term-cta:empty { display: none; }
.cta-label {
  font-size: 10px;
  letter-spacing: 0.24em;
  font-weight: 700;
  color: var(--accent);
  opacity: 0.9;
}
.cta-cmd {
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 16px;
  font-weight: 700;
  letter-spacing: 0.02em;
